    private array $cbMap = [];

    public function run(): void
    {
        $this->command->info("📦 تحميل خريطة الصناديق...");
        foreach (Cashbox::all() as $cb) {
            $this->cbMap[$cb->code] = $cb->id;
        }

        $this->command->info("💾 إدراج 448 حركة (IST-TRY - الجزء 2)...");

        $rows = $this->data();
        $now  = now()->toDateTimeString();
        $batch = [];
        $inserted = 0;

        foreach ($rows as $r) {
            $cbId = $this->cbMap[$r['cashbox_code']] ?? null;
            if (!$cbId) {
                $this->command->warn("  ⚠️ صندوق غير موجود: {$r['cashbox_code']}");
                continue;
            }

            $batch[] = [
                'cashbox_id'             => $cbId,
                'trx_date'               => $r['trx_date'],
                'type'                   => $r['type'],
                'amount'                 => $r['amount'],
                'currency'               => 'TRY',
                'category'               => $r['category'],
                'sub_category'           => $r['sub_category'],
                'foreign_currency'       => null,
                'foreign_amount'         => null,
                'reference'              => $r['reference'],
                'notes'                  => $r['notes'],
                'status'                 => 'posted',
                'posted_at'              => $r['trx_date'] . ' 12:00:00',
                'attachment_path'        => null,
                'to_cashbox_id'          => isset($r['to_cashbox_code']) && $r['to_cashbox_code']
                                            ? ($this->cbMap[$r['to_cashbox_code']] ?? null)
                                            : null,
                'exchange_to_cashbox_id' => isset($r['exchange_cashbox_code']) && $r['exchange_cashbox_code']
                                            ? ($this->cbMap[$r['exchange_cashbox_code']] ?? null)
                                            : null,
                'created_at'             => $now,
                'updated_at'             => $now,
            ];

            if (count($batch) >= 100) {
                CashboxTransaction::insert($batch);
                $inserted += count($batch);
                $batch = [];
                $this->command->line("  ⏳ {$inserted} / 448");
            }
        }

        if (!empty($batch)) {
            CashboxTransaction::insert($batch);
            $inserted += count($batch);
        }

        $this->command->info("  ✅ تم إدراج {$inserted} حركة");
    }

